import React, {useContext, useMemo} from "react";
import ChartContainer from "../WidgetContainer";
import {plugins} from "../helpers";
import {WidgetsContext} from "../context";
import {type IDoughnutChartProps} from "@lmb-it/kitsconcerto-types";
import {generateDoughnutData} from "../helpers/data";
import {type ChartOptions} from "chart.js";
import {Chart} from "primereact/chart";
import {Skeleton} from "primereact/skeleton";

const DoughnutChart = () => {
  const {
    isLoading,
    id = Math.random().toString(16).slice(2),
    data: dataProp,
    aspectRatio = 1,
    colors,
    isDarkMode,
  } = useContext(WidgetsContext);

  const { data } = dataProp as IDoughnutChartProps;

  const doughnutOptions = useMemo(() => {
    return {
      color: colors.labels,
      layout: {
        // padding: {
        //     top: 10,
        //     left: 10,
        //     bottom: 10
        // }
      },
      responsive: true,
      maintainAspectRatio: true,
      aspectRatio: aspectRatio,
      plugins: {
        legend: {
          position: "right" as
            | "right"
            | "top"
            | "bottom"
            | "left"
            | "center"
            | "chartArea",
          labels: {
            usePointStyle: true,
            font: {
              family: "Poppins, Helvetica, sans-serif",
              size: 12,
            },
          },
        },
      },
    } as ChartOptions<"doughnut">;
  }, [isDarkMode]);

  //
  return (
    <ChartContainer>
      {!isLoading ? (
        <Chart
          type={"doughnut"}
          id={id}
          options={doughnutOptions}
          width={"100%"}
          style={{
            justifyContent: "center",
            display: "flex",
          }}
          // height={'100%'}
          plugins={[plugins.doughnut(data.datasets.length)]}
          data={generateDoughnutData(data, isDarkMode)}
        />
      ) : (
        <Skeleton height="100%" width={"100%"} />
      )}
    </ChartContainer>
  );
};

export default DoughnutChart;
